class Solution(object):
    def maximumSubsequenceCount(self, text, pattern):
        p0, p1 = pattern[0], pattern[1]

        def count_subseq(s):
            cnt0 = cnt = 0
            for c in s:
                if c == p1:
                    cnt += cnt0
                if c == p0:
                    cnt0 += 1
            return cnt

        base = count_subseq(text)
        # Option 1: add p0 at the beginning
        opt1 = count_subseq(p0 + text)
        # Option 2: add p1 at the end
        opt2 = count_subseq(text + p1)
        return max(opt1, opt2)
